:root {
  font-size: 16px; /* Define base for rem units */
  --base-line-height: 1.5rem; /* Our consistent vertical rhythm grid unit (24px) */
}

body {
  font-family: 'Lato', sans-serif; /* Example web font */
  line-height: var(--base-line-height); /* Set base line-height for body text */
  color: #333;
  /* Improve text rendering for sharper UI/UX */
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

/* Apply tighter line-heights for headings but maintain consistent vertical spacing */
h1, h2, h3, h4, h5, h6 {
  line-height: 1.2; /* A common, tighter line-height for headings */
  margin-top: var(--base-line-height); /* Ensures consistent spacing above headings */
  margin-bottom: var(--base-line-height); /* Ensures consistent spacing below headings, aligning subsequent blocks */
}

/* Ensure all primary text blocks adhere to the vertical rhythm */
p, ul, ol, blockquote {
  line-height: var(--base-line-height); /* Consistent line-height for main text content */
  margin-bottom: var(--base-line-height); /* Align block elements to the grid */
}
